module noise_suppression(  
    input [4:0] noisy_data,  
    output reg [4:0] clean_signal  
);  
    always @(*) begin  
        if (noisy_data[2:0] == 3'b000) begin  
            clean_signal = 5'b00000;  
        end else begin  
            clean_signal = (noisy_data[2] + noisy_data[1] + noisy_data[0]) / 3;  
        end  
    end  
endmodule
